import React, { useMemo } from 'react';
import ProductCard from './ProductCard';

const allProducts = [
  { id: 1, name: 'Dell XPS 13 9315 (Sky Blue)', brand: 'Dell', image: 'https://via.placeholder.com/300', specs: ['Core i5', '16GB', '512GB SSD'], cpu: 'Core i5', ram: '16GB', price: 24990000, priceText: '24.990.000₫', oldPrice: '28.500.000₫', badge: '-12%' },
  { id: 2, name: 'MacBook Air M2 13-inch 2023', brand: 'Apple', image: 'https://via.placeholder.com/300', specs: ['M2 8-core', '8GB', '256GB SSD'], cpu: 'Apple M2', ram: '8GB', price: 26490000, priceText: '26.490.000₫' },
  { id: 3, name: 'Asus ROG Zephyrus G14 2024', brand: 'Asus', image: 'https://via.placeholder.com/300', specs: ['R9-7940HS', '16GB', 'RTX 4060'], cpu: 'Ryzen 5', ram: '16GB', price: 38990000, priceText: '38.990.000₫' },
  { id: 4, name: 'Lenovo ThinkPad X1 Carbon Gen 11', brand: 'Lenovo', image: 'https://via.placeholder.com/300', specs: ['Core i7', '32GB', '1TB SSD'], cpu: 'Core i7', ram: '32GB', price: 42500000, priceText: '42.500.000₫' },
  { id: 5, name: 'Microsoft Surface Pro 9 Platinum', brand: 'HP', image: 'https://via.placeholder.com/300', specs: ['Core i5', '16GB', '256GB SSD'], cpu: 'Core i5', ram: '16GB', price: 22800000, priceText: '22.800.000₫' },
  { id: 6, name: 'HP Spectre x360 14 (2023) Black', brand: 'HP', image: 'https://via.placeholder.com/300', specs: ['Core i7', '16GB', '512GB SSD'], cpu: 'Core i7', ram: '16GB', price: 31200000, priceText: '31.200.000₫' },
  { id: 7, name: 'Acer Swift Edge 16 OLED', brand: 'Asus', image: 'https://via.placeholder.com/300', specs: ['Ryzen 7', '16GB', 'OLED 4K'], cpu: 'Ryzen 5', ram: '16GB', price: 27500000, priceText: '27.500.000₫' },
  { id: 8, name: 'MSI Stealth 14 Studio Blue', brand: 'Asus', image: 'https://via.placeholder.com/300', specs: ['Core i7', 'RTX 4050', '16GB'], cpu: 'Core i7', ram: '16GB', price: 34990000, priceText: '34.990.000₫', badge: 'New' }
];

const ProductGrid = ({ filters, setFilters }) => {
  const filteredProducts = useMemo(() => {
    let result = [...allProducts];

    if (filters.brands.length > 0) {
      result = result.filter(p => filters.brands.includes(p.brand));
    }

    if (filters.cpu) {
      result = result.filter(p => p.cpu === filters.cpu);
    }

    if (filters.ram) {
      result = result.filter(p => p.ram === filters.ram);
    }

    if (filters.sort === 'price-asc') {
      result.sort((a, b) => a.price - b.price);
    } else if (filters.sort === 'price-desc') {
      result.sort((a, b) => b.price - a.price);
    }

    return result;
  }, [filters]);
  const sortOptions = [
    { value: 'newest', label: 'Mới nhất' },
    { value: 'bestseller', label: 'Bán chạy' },
    { value: 'price-asc', label: 'Giá thấp - cao' },
    { value: 'price-desc', label: 'Giá cao - thấp' }
  ];

  return (
    <section className="flex-1">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6 bg-white dark:bg-background-dark p-4 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
        <p className="text-sm"><span className="font-bold text-primary">{filteredProducts.length}</span> sản phẩm được tìm thấy</p>
        <div className="flex items-center gap-2 overflow-x-auto">
          <span className="text-sm text-slate-500 whitespace-nowrap">Sắp xếp:</span>
          {sortOptions.map((sort) => (
            <button 
              key={sort.value} 
              onClick={() => setFilters({ ...filters, sort: sort.value })}
              className={`px-3 py-1.5 text-xs ${filters.sort === sort.value ? 'bg-primary text-white' : 'bg-slate-100 dark:bg-slate-800'} rounded-lg whitespace-nowrap`}
            >
              {sort.label}
            </button>
          ))}
        </div>
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4">
        {filteredProducts.map(product => (
          <ProductCard key={product.id} product={{...product, price: product.priceText}} />
        ))}
      </div>
      <div className="flex justify-center mt-12 mb-8 gap-2">
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">
          <span className="material-symbols-outlined">chevron_left</span>
        </button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg bg-primary text-white font-bold">1</button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">2</button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">3</button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">
          <span className="material-symbols-outlined">chevron_right</span>
        </button>
      </div>
    </section>
  );
};

export default ProductGrid;
